import React, { useEffect, useState } from 'react';
import ProductForm from '../components/ProductForm';
import ProductList from '../components/ProductList';
import StockMovementForm from '../components/StockMovementForm';
import StockMovementList from '../components/StockMovementList'; 
import axios from 'axios';

const Products = () => {
    const [products, setProducts] = useState([]);
    const [movements, setMovements] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState(null);
    const [movement, setMovement] = useState({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
    const [isEditingMovement, setIsEditingMovement] = useState(false);
    const [currentMovementId, setCurrentMovementId] = useState(null);

    // Função para buscar produtos da API
    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            setProducts(response.data);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    // Função para buscar movimentações da API
    const fetchMovements = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/movimentacoes/');
            setMovements(response.data);
        } catch (error) {
            console.error("Erro ao buscar movimentações:", error);
        }
    };

    // Atualizar produto no banco e na lista
    const updateProductQuantity = async (productId, tipoMovimentacao, quantidade_minima) => {
        try {
            const produto = products.find(p => p.id === productId);
            if (!produto) return;

            const novaQuantidade = tipoMovimentacao === 'entrada'
                ? produto.quantidade_minima + quantidade_minima
                : produto.quantidade_minima - quantidade_minima;

            if (novaQuantidade < 0) {
                console.error("Quantidade não pode ser negativa");
                return; // Adicione uma validação para impedir quantidades negativas
            }

            await axios.put(`http://127.0.0.1:8000/api/produtos/${productId}/`, {
                quantidade_minima: novaQuantidade
            });

            // Atualiza a lista de produtos localmente
            setProducts(prevProducts => {
                return prevProducts.map(p => 
                    p.id === productId ? { ...p, quantidade_minima: novaQuantidade } : p
                );
            });
        } catch (error) {
            console.error("Erro ao atualizar quantidade do produto:", error);
        }
    };

    // Deletar um produto
    const handleDelete = async (productId) => {
        try {
            await axios.delete(`http://127.0.0.1:8000/api/produtos/${productId}/`);
            fetchProducts(); // Atualiza a lista após deletar
        } catch (error) {
            console.error("Erro ao deletar produto:", error);
        }
    };

    const handleEditMovement = (movement) => {
        setMovement({
            produto: movement.produto,
            tipo_movimentacao: movement.tipo_movimentacao,
            quantidade: movement.quantidade,
            motivo: movement.motivo
        });
        setIsEditingMovement(true);
        setCurrentMovementId(movement.id); // Armazena o ID da movimentação a ser editada
    };

    useEffect(() => {
        fetchProducts();
        fetchMovements(); // Busca as movimentações quando o componente é montado
    }, []);

    return (
        <div>
            <h2>Gerenciar Produtos</h2>
            <ProductForm 
                refreshProducts={fetchProducts} 
                selectedProduct={selectedProduct} 
                setSelectedProduct={setSelectedProduct} 
            />
            <ProductList 
                products={products} 
                onEdit={setSelectedProduct} 
                onDelete={handleDelete} 
            />
            <h2>Movimentação de Estoque</h2>
            <StockMovementForm 
                refreshProducts={fetchProducts} 
                updateProductQuantity={updateProductQuantity} 
                isEditing={isEditingMovement} 
                currentMovementId={currentMovementId} 
                movement={movement} 
            />
            <StockMovementList 
                movements={movements} 
                onEdit={handleEditMovement} // Passa a função de edição
            />
        </div>
    );
};

export default Products;
